import './App.css';
import ShapeGrid from './component/ShapeGrid';

function App() {
  return (
    <div className="App">
      <div className="shapegrid-shell">
        <ShapeGrid
          speed={0.5}
          squareSize={40}
          direction="diagonal"
          borderColor="#050505"
          hoverFillColor="#000000"
          shape="square"
          hoverTrailAmount={0}
        />
      </div>
      <nav className="glass-navbar" aria-label="Primary">
        <a href="/" className="glass-navbar__brand">
          Planora
        </a>
        <div className="glass-navbar__links">
          <a href="/">Home</a>
          <a href="/">Explore</a>
          <a href="/">About</a>
          <a href="/">Contact</a>
        </div>
      </nav>
    </div>
  );
}

export default App;
